def listprime(lp):
    prime=[True]*lp
    prime[0]=False
    prime[1]=False
    for x in range(lp):
        if prime[x]:
            bei=x+x
            while bei<lp:
                prime[bei]=False
                bei+=x
    return prime

def replaceStar(s):
    result=[]
    if '*' in s:
        for n in range(0,9+1):
            news = s.replace('*', str(n))
            if news[0]!='0':
                result.append(news)
    else:
        result.append(s)
    return result

